package ru.memearena.meme.api; import jakarta.validation.Valid; import jakarta.validation.constraints.*; import org.springframework.web.bind.annotation.*; import ru.memearena.media.infrastructure.MediaAssetRepository; import ru.memearena.meme.application.MemeService; import ru.memearena.meme.domain.ModerationStatus; import ru.memearena.user.infrastructure.UserProfileRepository; import java.util.*;
@RestController @RequestMapping("/api/v1/admin/moderation/memes") public class AdminMemeModerationController { private final MemeService service; private final UserProfileRepository users; private final MediaAssetRepository media; public AdminMemeModerationController(MemeService service,UserProfileRepository users,MediaAssetRepository media){this.service=service;this.users=users;this.media=media;} @GetMapping public ModerationQueueResponse queue(@RequestParam(defaultValue="PENDING") ModerationStatus status,@RequestParam(defaultValue="0") @Min(0) int page,@RequestParam(defaultValue="20") @Min(1) @Max(100) int size){var p=service.moderationQueue(status,page,size); var items=p.getContent().stream().map(m->ModerationMemeItemResponse.of(m,users.findById(m.getUploaderId()).map(u->u.getNickname()).orElse(null))).toList(); return new ModerationQueueResponse(items,page,size,p.getTotalElements(),p.getTotalPages());} @GetMapping("/{memeId}") public ModerationMemeItemResponse one(@PathVariable UUID memeId){var m=service.get(memeId); return ModerationMemeItemResponse.of(m,users.findById(m.getUploaderId()).map(u->u.getNickname()).orElse(null));} @PostMapping("/{memeId}/approve") public MemeResponse approve(@PathVariable UUID memeId){return MemeResponse.from(service.approve(memeId));} @PostMapping("/{memeId}/reject") public MemeResponse reject(@PathVariable UUID memeId,@Valid @RequestBody RejectMemeRequest r){return MemeResponse.from(service.reject(memeId,r.reason()));} }
